transform_js:
var h = Math.sqrt(3) / 2;
var transformDataFunc = function(rows) {
  return rows.map(function(r) {
    var total = r.carb + r.protein + r.fat;
    var c_ratio = r.carb / total;
    var p_ratio = r.protein / total;
    var f_ratio = r.fat / total;
    // bottom-left: Carb, bottom-right: Protein, top: Fat
    var x = 0.5 * (2 * p_ratio + f_ratio);
    var y = h * f_ratio;
    return { name: r.label, value: [x, y], carb: r.carb, protein: r.protein, fat: r.fat, group: r.group };
  });
};
transformedData = transformDataFunc(rawData.rows);

echarts_js:
var h = Math.sqrt(3) / 2;
function getScaling(params) {
  var width = params.coordSys.width;
  var height = params.coordSys.height;
  var padding = 40;
  var side = Math.min(width - padding * 2, (height - padding * 2) / h);
  var xOffset = (width - side) / 2;
  var yOffset = (height - side * h) / 2 + side * h; 
  return { side: side, x: params.coordSys.x + xOffset, y: params.coordSys.y + yOffset };
}

var groups = ['和食・ヘルシー', 'ファストフード・洋食', '筋トレ・アスリート'];
var colors = ['#3ba272', '#ee6666', '#5470c6'];
var shapes = ['circle', 'rect', 'triangle'];

// dummy series array, echarts sometimes needs at least 1 config
var series = [
  {
    name: 'Background',
    type: 'custom',
    renderItem: function(params, api) {
      if (params.dataIndex !== 0) return;
      var s = getScaling(params);
      function map(pt) { return [s.x + pt[0] * s.side, s.y - pt[1] * s.side]; }
      var pCarb = map([0, 0]), pProtein = map([1, 0]), pFat = map([0.5, h]);
      var children = [
        { type: 'polygon', shape: { points: [pCarb, pProtein, pFat] }, style: { fill: '#fcfcfc', stroke: '#ccc', lineWidth: 1 } }
      ];
      // Grid lines
      [0.2, 0.4, 0.6, 0.8].forEach(function(v) {
        children.push({ type: 'line', shape: { x1: map([v, 0])[0], y1: map([v, 0])[1], x2: map([v/2 + 0.5, h*(1-v)])[0], y2: map([v/2 + 0.5, h*(1-v)])[1] }, style: { stroke: '#eee', lineWidth: 1, lineDash: [3, 3] } });
        children.push({ type: 'line', shape: { x1: map([1-v, 0])[0], y1: map([1-v, 0])[1], x2: map([0.5 - v/2, h*(1-v)])[0], y2: map([0.5 - v/2, h*(1-v)])[1] }, style: { stroke: '#eee', lineWidth: 1, lineDash: [3, 3] } });
        children.push({ type: 'line', shape: { x1: map([v/2, h*v])[0], y1: map([v/2, h*v])[1], x2: map([1 - v/2, h*v])[0], y2: map([1 - v/2, h*v])[1] }, style: { stroke: '#eee', lineWidth: 1, lineDash: [3, 3] } });
      });
      // labels
      children.push({ type: 'text', style: { text: '炭水化物\n(100%)', x: pCarb[0], y: pCarb[1] + 10, align: 'center', verticalAlign: 'top', fill: '#666', font: 'bold 12px sans-serif' } });
      children.push({ type: 'text', style: { text: 'タンパク質\n(100%)', x: pProtein[0], y: pProtein[1] + 10, align: 'center', verticalAlign: 'top', fill: '#666', font: 'bold 12px sans-serif' } });
      children.push({ type: 'text', style: { text: '脂質\n(100%)', x: pFat[0], y: pFat[1] - 10, align: 'center', verticalAlign: 'bottom', fill: '#666', font: 'bold 12px sans-serif' } });
      return { type: 'group', children: children };
    },
    data: [0], silent: true, z: 0
  }
];

groups.forEach(function(groupName, i) {
  var groupData = transformedData.filter(function(d) { return d.group === groupName; });
  if (groupData.length > 0) {
      series.push({
        name: groupName,
        type: 'custom',
        renderItem: function(params, api) {
          var s = getScaling(params);
          var pt = [s.x + api.value(0) * s.side, s.y - api.value(1) * s.side];

          if (shapes[i] === 'circle') {
              return { type: 'circle', shape: { cx: pt[0], cy: pt[1], r: 6 }, style: { fill: colors[i], stroke: '#fff', lineWidth: 1, opacity: 0.8 } };
          } else if (shapes[i] === 'rect') {
              return { type: 'rect', shape: { x: pt[0]-5, y: pt[1]-5, width: 10, height: 10 }, style: { fill: colors[i], stroke: '#fff', lineWidth: 1, opacity: 0.8 } };
          } else {
              return { type: 'polygon', shape: { points: [[pt[0], pt[1]-6], [pt[0]+6, pt[1]+4], [pt[0]-6, pt[1]+4]] }, style: { fill: colors[i], stroke: '#fff', lineWidth: 1, opacity: 0.8 } };
          }
        },
        data: groupData,
        z: 10
      });
  }
});

option = {
  title: { text: 'PFC Balance (三大栄養素)', left: 'center', top: 10 },
  tooltip: { formatter: function(p) { var d = p.data; return d.name + ' (' + d.group + ')<br/>炭水化物: ' + d.carb + '%<br/>タンパク質: ' + d.protein + '%<br/>脂質: ' + d.fat + '%'; } },
  legend: { top: 40, data: groups },
  grid: { top: 85, bottom: 40, left: 40, right: 40 },
  xAxis: { show: false, min: 0, max: 1 },
  yAxis: { show: false, min: 0, max: h },
  series: series
};
